-- Comprehensive Arabic seed for support_categories.
--
-- The seed in 20260428150000 didn't land in production (the table
-- exists but رows are empty), so this migration re-seeds idempotently.
-- ON CONFLICT (id) DO NOTHING means rows that already exist stay
-- untouched, and any subset that's missing gets filled in. Safe to
-- re-run.
--
-- Naming convention for the deterministic UUIDs below:
--   - Top-level categories use the 11111111-… prefix.
--   - Subcategories use the 22222222-… prefix, with the 9th group
--     digit identifying their parent (Bug=1, Question=2, Feature=3,
--     Billing=4, Account=5, Training=6, Other=9).

-- ─── Top-level categories ──────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ─── Bug subcategories — mirror the agent feature surface so a
--     reporter can pinpoint exactly where the issue sits.
ON CONFLICT (id) DO NOTHING;

-- ─── Question subcategories ────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ─── Feature-request subcategories ─────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ─── Billing subcategories ─────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ─── Account & Users subcategories ─────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ─── Training subcategories ────────────────────────────────────
ON CONFLICT (id) DO NOTHING;
